import { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import API from "../api/axios";

const EditPostPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user, loading } = useAuth();

  const [title, setTitle] = useState("");
  const [body, setBody] = useState("");
  const [image, setImage] = useState(null);

  const [preview, setPreview] = useState("");
  const [error, setError] = useState("");
  const [saving, setSaving] = useState(false);
  const [fetching, setFetching] = useState(true);

  const [darkMode, setDarkMode] = useState(false);

  /* LOAD DARK MODE (same logic as PostPage/HomePage) */
  useEffect(() => {
    const saved = localStorage.getItem("user-theme");
    setDarkMode(saved === "dark");
  }, []);

  const theme = {
    page: {
      minHeight: "90vh",
      display: "flex",
      justifyContent: "center",
      alignItems: "center",
      padding: "30px",
      background: darkMode
        ? "#121212"
        : "linear-gradient(135deg, #f7c6d9, #ffffff)",
    },

    card: {
      width: "100%",
      maxWidth: "650px",
      background: darkMode ? "#1e1e1e" : "#fff",
      padding: "30px",
      borderRadius: "20px",
      boxShadow: darkMode
        ? "0 0 15px rgba(0,0,0,0.6)"
        : "0 10px 25px rgba(0,0,0,0.1)",
      color: darkMode ? "#eee" : "#000",
    },

    input: {
      width: "100%",
      padding: "12px",
      marginBottom: "12px",
      borderRadius: "10px",
      border: darkMode ? "1px solid #444" : "1px solid #ccc",
      background: darkMode ? "#2a2a2a" : "#fff",
      color: darkMode ? "#fff" : "#000",
      outline: "none",
    },

    textarea: {
      width: "100%",
      height: "140px",
      padding: "12px",
      marginBottom: "12px",
      borderRadius: "10px",
      border: darkMode ? "1px solid #444" : "1px solid #ccc",
      background: darkMode ? "#2a2a2a" : "#fff",
      color: darkMode ? "#fff" : "#000",
      resize: "none",
      outline: "none",
    },

    button: {
      width: "100%",
      padding: "12px",
      borderRadius: "10px",
      border: "none",
      background: saving ? "#999" : "#1a4120",
      color: "white",
      fontWeight: "bold",
      cursor: saving ? "not-allowed" : "pointer",
      transition: "0.3s",
    },

    fileWrapper: {
      marginBottom: "12px",
      position: "relative",
    },

    fileInput: {
      display: "none",
    },

    fileLabel: {
      display: "inline-block",
      padding: "10px 15px",
      borderRadius: "10px",
      background: darkMode ? "#f7c6d9" : "#1a4120",
      color: darkMode ? "#000" : "#fff",
      cursor: "pointer",
      fontWeight: "bold",
      marginBottom: "10px",
    },

    preview: {
      width: "100%",
      borderRadius: "15px",
      marginTop: "10px",
      maxHeight: "320px",
      objectFit: "cover",
      border: darkMode ? "1px solid #444" : "2px solid #f7c6d9",
    },

    error: {
      background: "#ff4d6d",
      color: "white",
      padding: "10px",
      borderRadius: "10px",
      marginBottom: "15px",
      textAlign: "center",
    },
  };

  useEffect(() => {
    const fetchPost = async () => {
      try {
        const res = await API.get(`/posts/${id}`);
        setTitle(res.data.title);
        setBody(res.data.body);
        setPreview(
          res.data.image
            ? `http://localhost:5000/uploads/${res.data.image}`
            : ""
        );
      } catch (err) {
        setError("Failed to load post.");
      } finally {
        setFetching(false);
      }
    };

    fetchPost();
  }, [id]);

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    setImage(file);

    if (file) {
      setPreview(URL.createObjectURL(file));
    }
  };

  const handleUpdate = async (e) => {
    e.preventDefault();
    setSaving(true);
    setError("");

    try {
      const formData = new FormData();
      formData.append("title", title);
      formData.append("body", body);

      if (image) {
        formData.append("image", image);
      }

      await API.put(`/posts/${id}`, formData, {
        headers: { "Content-Type": "multipart/form-data" },
      });

      navigate(`/posts/${id}`);
    } catch (err) {
      setError("Failed to update post.");
    } finally {
      setSaving(false);
    }
  };

  if (loading || fetching) {
    return (
      <div style={{ textAlign: "center", padding: "50px" }}>
        Loading post...
      </div>
    );
  }

  if (!user) {
    return (
      <div style={{ textAlign: "center", padding: "50px", color: "red" }}>
        Unauthorized access.
      </div>
    );
  }

  return (
    <div style={theme.page}>

      <div style={theme.card}>

        <h2 style={{ textAlign: "center", marginBottom: "20px" }}>
          ✏️ Edit Post
        </h2>

        {error && <div style={theme.error}>{error}</div>}

        <form onSubmit={handleUpdate}>

          {/* TITLE */}
          <input
            type="text"
            placeholder="Post title"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            required
            style={theme.input}
          />

          {/* BODY */}
          <textarea
            placeholder="Write your post..."
            value={body}
            onChange={(e) => setBody(e.target.value)}
            required
            style={theme.textarea}
          />

          {/* FILE UPLOAD (CUSTOM BUTTON) */}
          <div style={theme.fileWrapper}>
            <label htmlFor="fileUpload" style={theme.fileLabel}>
              📁 Choose Image
            </label>

            <input
              id="fileUpload"
              type="file"
              onChange={handleImageChange}
              style={theme.fileInput}
            />
          </div>

          {/* PREVIEW */}
          {preview && (
            <img src={preview} alt="preview" style={theme.preview} />
          )}

          {/* SUBMIT */}
          <button type="submit" disabled={saving} style={theme.button}>
            {saving ? "Updating..." : "Update Post"}
          </button>

        </form>
      </div>
    </div>
  );
};

export default EditPostPage;
